var driveAway = {
  isOn: function () { return this.lastTriggerDate + 300 > Date.now(); },
  trigger: function () { this.lastTriggerDate = Date.now(); },
  lastTriggerDate: new Date(0)
}

var backOff = {
  isOn: function () { return this.lastTriggerDate + 2000 > Date.now(); },
  trigger: function (direction) { this.lastTriggerDate = Date.now(); this.direction = direction },
  lastTriggerDate: new Date(0),
  direction: 0
}

function transform(
  /** @type {TransformInput} */ input,
  /** @type {number} */ dt,
  /** @type {Record<string, unknown>} */ params,
  /** @type {Record<string, unknown>} */ state,
  /** @type {TransformerRuntimeApi} */ api,
) {
  if (api.getAction(input, 'steer_left') || api.getAction(input, 'steer_right' || api.getAction(input, 'throttle') || api.getAction(input, 'brake'))) return;

  let forward = api.getForwardVector(input.rotation);
  let targetPos = input.target.pose.position;
  let inputToTarget = api.vec.subtract(targetPos, input.position);
  const distance = api.vec.length(inputToTarget);

  // Zero out Y (index 1) so everything stays on the X/Z plane
  forward[1] = 0;
  inputToTarget[1] = 0;

  // Normalize
  forward = api.vec.normalize(forward);
  inputToTarget = api.vec.normalize(inputToTarget);

  // Dot product and angle
  let dot = api.vec.dot(forward, inputToTarget);
  dot = Math.max(-1, Math.min(1, dot));
  let angle = Math.acos(dot);

  let cross = api.vec.cross(forward, inputToTarget);

  if (Math.abs(angle) < 0.001) {
  } else if (cross[1] > 0) {
    input.actions.steering_angle = angle;
  } else {
    input.actions.steering_angle = -angle;
  }
  const maxSpeed = 120
  const approachspeed = 3;
  const approachDist = 10;
  const turnSpeed = 20;
  const driveAwayDistance = 15;
  let targetSpeed = 80;

  //api.log("distance: " + distance + "angle: " + angle);
  if (distance < approachDist) targetSpeed = approachspeed;
  if (Math.abs(angle) > 1) targetSpeed = turnSpeed;
  if (targetSpeed > maxSpeed) targetSpeed = maxSpeed;

  if (distance < driveAwayDistance && angle > .2) {
    driveAway.trigger();
    api.log("DRIVEAWAY")
  };

  let currentSpeed = api.vec.length(input.velocity);

  if (driveAway.isOn()) {
    targetSpeed = maxSpeed;
    input.actions.steering_angle = 0;
  }

  if (backOff.isOn()) {
    input.actions.brake = 0.5;
    input.actions.throttle = 0;
    input.actions.steering_angle = backOff.direction;
    return;
  } else {
    if (multiRaycast(api, api.vec.add(input.position, api.vec.scale(forward, 5)), forward, 1, 2, 10).hit === true) {
      let direction = -input.actions.steering_angle;
      if(Math.abs(direction)<0.2 || !direction) direction = Math.random(2) - 1;
      backOff.trigger(direction);
      api.log("BACKOFF " + direction);
    }
  }
  if (targetSpeed > currentSpeed) input.actions.throttle = 1;
}

/** @return {RaycastResult | undefined} */
function multiRaycast(
  /** @type {TransformerRuntimeApi} */ api,
  /** @type {Vec3} */ origin,
  /** @type {Vec3} */ forward,
  /** @type {number} */ distance,
  /** @type {number} */ lateralRange,
  /** @type {number} */ count
) {
  const right = api.vec.normalize(api.vec.cross(forward, [0, 1, 0]));

  const hits = [];

  for (let i = 0; i < count; i++) {
    // Map i to [-1, 1] across lateralRange, centered at 0
    const t = count === 1 ? 0 : (i / (count - 1)) * 2 - 1;
    const offset = api.vec.scale(right, t * lateralRange);
    const rayOrigin = api.vec.add(origin, offset);
    const cast = raycast(api, rayOrigin, forward, distance);
    if (cast.hit) hits.push(cast);
  }

  hits.sort((a, b) => a.distance - b.distance);

  // Fallback: center ray (t=0), re-cast if not already in hits
  return hits[0] ?? raycast(api, origin, forward, distance);
}


